module RefModule(

               topsig,

               clk
               );input  clk;
   output topsig;



   reg    topsig;
`define TOPSIG  {topsig}

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt) begin
      `TOPSIG <= #0 1'b1;
   end

   task direct_write;
      input val;
      begin
         `TOPSIG = val;
      end
   endtask
endmodule
